const firstNames = ['Minh', 'Hùng', 'Lan', 'Vy', 'Tuấn', 'Dũng', 'Giang', 'Hương', 'Linh', 'Quang', 'Đức', 'Thảo', 'Trang', 'Nam', 'Việt', 'Bảo', 'Ngọc', 'Tâm', 'Sơn', 'Hà'];
