import React, { useState } from 'react';
import Layout from './components/Layout';
import Home from './pages/Home';
import Activities from './pages/Activities';
import Leaderboard from './pages/Leaderboard';
import Events from './pages/Events';
import Profile from './pages/Profile';
import Blog from './pages/Blog';
import BlogDetail from './pages/BlogDetail';
import Gallery from './pages/Gallery';
import About from './pages/About';
import Contact from './pages/Contact';
import Rules from './pages/Rules';
import Partners from './pages/Partners';
import Login from './pages/Login';
import Register from './pages/Register';
import ForgotPassword from './pages/ForgotPassword';
import NotFound from './pages/NotFound';
import Challenges from './pages/Challenges';
import ChallengeDetail from './pages/ChallengeDetail';
import { USERS, BLOG_POSTS, CHALLENGES } from './constants';
import { User, BlogPost } from './types';

const App: React.FC = () => {
  // Router state
  const [currentPage, setCurrentPage] = useState('home');
  const [selectedPostId, setSelectedPostId] = useState<string | null>(null);
  const [selectedChallengeId, setSelectedChallengeId] = useState<string | null>(null);

  // Mock Auth state
  const [user, setUser] = useState<User | null>(null);

  const handleLogin = () => {
    // Simulate Login
    setTimeout(() => {
       setUser(USERS[0]); // Log in as "Minh Nguyen"
       setCurrentPage('home');
    }, 500);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
  };

  const navigateTo = (page: string, params?: any) => {
    window.scrollTo(0, 0);
    if (page === 'blog-detail' && params?.id) {
        setSelectedPostId(params.id);
    }
    if (page === 'challenge-detail' && params?.id) {
        setSelectedChallengeId(params.id);
    }
    setCurrentPage(page);
  };

  // Pages that don't use the Main Layout (Auth pages, 404)
  if (currentPage === 'login') return <Login onNavigate={navigateTo} onLogin={handleLogin} />;
  if (currentPage === 'register') return <Register onNavigate={navigateTo} />;
  if (currentPage === 'forgot-password') return <ForgotPassword onNavigate={navigateTo} />;
  if (currentPage === '404') return <NotFound onNavigate={navigateTo} />;

  const renderPage = () => {
    switch (currentPage) {
      case 'home':
        return <Home onJoin={() => navigateTo('register')} onNavigate={navigateTo} />;
      case 'activities':
        return <Activities onJoin={() => navigateTo('register')} onNavigate={navigateTo} />;
      case 'challenges':
        return <Challenges onNavigate={navigateTo} />;
      case 'challenge-detail':
        const challenge = CHALLENGES.find(c => c.id === selectedChallengeId);
        return challenge ? <ChallengeDetail challenge={challenge} onNavigate={navigateTo} /> : <NotFound onNavigate={navigateTo} />;
      case 'leaderboard':
        return <Leaderboard />;
      case 'events':
        return <Events />;
      case 'profile':
        return user ? <Profile user={user} /> : <Login onNavigate={navigateTo} onLogin={handleLogin} />; // Redirect to login if accessing profile
      case 'blog':
        return <Blog onNavigate={navigateTo} />;
      case 'blog-detail':
        const post = BLOG_POSTS.find(p => p.id === selectedPostId);
        return post ? <BlogDetail post={post} onNavigate={navigateTo} /> : <NotFound onNavigate={navigateTo} />;
      case 'gallery':
        return <Gallery />;
      case 'about':
        return <About />;
      case 'contact':
        return <Contact />;
      case 'rules':
        return <Rules />;
      case 'partners':
        return <Partners />;
      default:
        return <NotFound onNavigate={navigateTo} />;
    }
  };

  return (
    <Layout 
      currentPage={currentPage} 
      onNavigate={navigateTo}
      user={user}
      onLogin={() => navigateTo('login')}
      onLogout={handleLogout}
    >
      {renderPage()}
    </Layout>
  );
};

export default App;

import React, { useMemo } from 'react';
import { Challenge, User } from '../types';
import { USERS } from '../constants';
import { Calendar, Users, Target, ArrowLeft, Info, CheckCircle, Zap, Activity } from 'lucide-react';

interface ChallengeDetailProps {
  challenge: Challenge;
  onNavigate: (page: string) => void;
}

const ChallengeDetail: React.FC<ChallengeDetailProps> = ({ challenge, onNavigate }) => {
  // Generate random leaderboard data based on USERS constant
  const leaderboard = useMemo(() => {
    // Deterministic random generator based on seed (challenge.id)
    const seededRandom = (seed: number) => {
        const x = Math.sin(seed++) * 10000;
        return x - Math.floor(x);
    };

    return USERS.map((user, index) => {
        // Base seed on user and challenge
        const seed = user.id.charCodeAt(0) + challenge.id.charCodeAt(1);
        const rand = seededRandom(seed);

        // Random Stats
        const runs = Math.floor(rand * 20) + 5; // 5 to 25 runs
        const paceMin = 3 + Math.floor(rand * 4); // 3 to 6
        const paceSec = Math.floor(rand * 60);
        const paceStr = `${paceMin}:${paceSec.toString().padStart(2, '0')}`;

        // Distance Logic (some beat target heavily, some under)
        // Ensure top users beat it
        let totalKm = 0;
        if (index < 5) {
             totalKm = challenge.targetDistance + (rand * 200); // Top 5 always beat + extra
        } else {
             totalKm = challenge.targetDistance * (rand * 1.5); // Others random
        }

        const percent = Math.floor((totalKm / challenge.targetDistance) * 100);
        const isCompleted = totalKm >= challenge.targetDistance;
        const surplus = totalKm - challenge.targetDistance;

        return {
            user,
            runs,
            pace: paceStr,
            totalKm: parseFloat(totalKm.toFixed(1)),
            percent,
            isCompleted,
            surplus: parseFloat(surplus.toFixed(1))
        };
    }).sort((a, b) => b.totalKm - a.totalKm); // Sort by distance DESC
  }, [challenge]);

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement>) => {
    e.currentTarget.src = 'https://images.unsplash.com/photo-1552674605-469523f9bc9d?auto=format&fit=crop&q=80&w=800';
  };

  return (
    <div className="animate-fade-in bg-gray-50 min-h-screen pb-12">
      {/* Back Button */}
      <div className="bg-white border-b border-gray-100 sticky top-16 z-20">
          <div className="max-w-4xl mx-auto px-4 py-3">
              <button onClick={() => onNavigate('challenges')} className="flex items-center text-slate-500 hover:text-orange-600 transition-colors font-medium">
                  <ArrowLeft size={20} className="mr-2" /> Quay lại danh sách
              </button>
          </div>
      </div>

      {/* Hero Header */}
      <div className="relative h-64 md:h-80 overflow-hidden">
          <img 
            src={challenge.imageUrl} 
            alt={challenge.title} 
            className="w-full h-full object-cover"
            onError={handleImageError}
          />
          <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-slate-900/60 to-transparent"></div>
          <div className="absolute bottom-0 left-0 w-full p-6 md:p-10 max-w-4xl mx-auto text-white">
              <span className={`inline-block px-3 py-1 rounded-md text-xs font-bold uppercase tracking-wider mb-3 ${challenge.status === 'Active' ? 'bg-green-500' : 'bg-gray-500'}`}>
                  {challenge.status === 'Active' ? 'Đang diễn ra' : 'Đã kết thúc'}
              </span>
              <h1 className="text-3xl md:text-5xl font-display font-bold mb-2">{challenge.title}</h1>
              <div className="flex flex-wrap gap-4 text-sm md:text-base text-slate-200">
                  <span className="flex items-center"><Calendar size={18} className="mr-1.5" /> {challenge.startDate} - {challenge.endDate}</span>
                  <span className="flex items-center"><Target size={18} className="mr-1.5" /> Mục tiêu: {challenge.targetDistance} km</span>
                  <span className="flex items-center"><Users size={18} className="mr-1.5" /> {challenge.participants} runners</span>
              </div>
          </div>
      </div>

      <div className="max-w-4xl mx-auto px-4 -mt-8 relative z-10 space-y-8">

          {/* Rules & Info Card */}
          <div className="bg-white rounded-xl shadow-lg border border-gray-100 p-6 md:p-8">
              <div className="flex items-center mb-4">
                  <Info className="text-orange-600 mr-2" size={24} />
                  <h2 className="text-xl font-bold text-slate-900">Thông tin & Quy định</h2>
              </div>
              <p className="text-slate-600 mb-6 leading-relaxed">{challenge.description}</p>

              {challenge.rules && challenge.rules.length > 0 && (
                  <div className="bg-orange-50 rounded-lg p-5 border border-orange-100">
                      <h3 className="font-bold text-orange-800 mb-3 text-sm uppercase tracking-wide">Quy định thử thách</h3>
                      <ul className="space-y-2">
                          {challenge.rules.map((rule, idx) => (
                              <li key={idx} className="flex items-start text-sm text-slate-700">
                                  <span className="mr-2 mt-1 text-orange-500">•</span>
                                  <span>{rule}</span>
                              </li>
                          ))}
                      </ul>
                  </div>
              )}
          </div>

          {/* Detailed Leaderboard */}
          <div className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden">
              <div className="p-6 border-b border-gray-100 bg-slate-50 flex justify-between items-center">
                  <h2 className="text-xl font-bold text-slate-900 flex items-center">
                      <Activity className="mr-2 text-orange-600" /> Bảng Xếp Hạng Chi Tiết
                  </h2>
                  <span className="text-xs font-bold text-slate-500 bg-white border border-gray-200 px-3 py-1 rounded-full">
                      Top {leaderboard.length} Runners
                  </span>
              </div>

              <div className="divide-y divide-gray-100">
                  {leaderboard.map((item, idx) => (
                      <div key={item.user.id} className="p-4 md:p-6 hover:bg-orange-50/30 transition-colors group">
                          <div className="flex flex-col md:flex-row md:items-center gap-4">

                              {/* Rank & User Info */}
                              <div className="flex items-center min-w-[200px]">
                                  <div className={`
                                      flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full flex items-center justify-center font-bold text-sm md:text-base mr-3 md:mr-4
                                      ${idx === 0 ? 'bg-yellow-100 text-yellow-700 border border-yellow-300' : 
                                        idx === 1 ? 'bg-gray-100 text-slate-700 border border-gray-300' : 
                                        idx === 2 ? 'bg-orange-100 text-orange-800 border border-orange-300' : 'bg-white text-slate-500 border border-gray-200'}
                                  `}>
                                      {idx + 1}
                                  </div>
                                  <img src={item.user.avatar} alt="Avatar" className="w-12 h-12 rounded-full border-2 border-white shadow-sm mr-3" />
                                  <div>
                                      <div className="font-bold text-slate-900 text-base md:text-lg leading-tight">{item.user.firstName} {item.user.lastName}</div>
                                      <div className="flex items-center text-xs text-slate-500 mt-1 space-x-2">
                                          <span className="flex items-center bg-slate-100 px-1.5 py-0.5 rounded">
                                              {/* Simple logic for gender based on ID for demo */}
                                              {item.user.id.charCodeAt(1) % 2 === 0 ? '👨 Nam' : '👩 Nữ'}
                                          </span>
                                          <span>Lvl {item.user.level}</span>
                                      </div>
                                  </div>
                              </div>

                              {/* Stats Grid - Mobile optimized */}
                              <div className="flex-grow grid grid-cols-2 md:grid-cols-4 gap-2 md:gap-4 text-sm mt-2 md:mt-0">
                                  <div className="md:text-center">
                                      <div className="text-xs text-slate-400 uppercase font-semibold">Pace TB</div>
                                      <div className="font-medium text-slate-700 flex items-center md:justify-center">
                                          <Zap size={14} className="text-orange-500 mr-1" /> {item.pace}
                                      </div>
                                  </div>
                                  <div className="md:text-center">
                                      <div className="text-xs text-slate-400 uppercase font-semibold">Hoạt động</div>
                                      <div className="font-medium text-slate-700 flex items-center md:justify-center">
                                          <Activity size={14} className="text-blue-500 mr-1" /> {item.runs} lần chạy
                                      </div>
                                  </div>
                                  <div className="col-span-2 md:col-span-2">
                                      <div className="flex justify-between items-end mb-1">
                                          <div className="text-xs text-slate-500">
                                              <span className="font-bold text-slate-900 text-base">{item.totalKm}</span>
                                              <span className="text-slate-400">/{challenge.targetDistance} km</span>
                                          </div>
                                          <div className={`text-xs font-bold ${item.isCompleted ? 'text-green-600' : 'text-slate-500'}`}>
                                              {item.percent}%
                                          </div>
                                      </div>
                                      <div className="w-full bg-gray-100 rounded-full h-2.5 overflow-hidden">
                                          <div 
                                              className={`h-full rounded-full ${item.isCompleted ? 'bg-gradient-to-r from-green-500 to-green-600' : 'bg-gradient-to-r from-orange-400 to-orange-600'}`}
                                              style={{ width: `${Math.min(item.percent, 100)}%` }}
                                          ></div>
                                      </div>
                                      {item.isCompleted && (
                                          <div className="mt-1 text-[11px] md:text-xs font-bold text-green-600 flex items-center">
                                              <CheckCircle size={12} className="mr-1" />
                                              Đã hoàn thành vượt mức +{item.surplus} km!
                                          </div>
                                      )}
                                  </div>
                              </div>

                              {/* Big Total for Desktop */}
                              <div className="hidden md:flex flex-col items-end min-w-[80px]">
                                  <div className="text-2xl font-display font-bold text-slate-900">{Math.floor(item.totalKm)}</div>
                                  <div className="text-xs font-bold text-slate-400 uppercase">KM</div>
                              </div>

                          </div>
                      </div>
                  ))}
              </div>
          </div>
      </div>
    </div>
  );
};

