                        <tbody className="divide-y divide-gray-50">
                           {registrants.length > 0 ? registrants.map((reg, idx) => (
                              <tr key={`${reg.user.id}-${idx}`} className="hover:bg-slate-50 transition-colors">
                                 <td className="px-6 py-4">
