import React, { useState, useEffect, useCallback } from 'react';
import { GALLERY_ALBUMS } from '../constants';
import { Album } from '../types';
import { Camera, Image as ImageIcon, X, ChevronLeft, ChevronRight, Calendar, MapPin } from 'lucide-react';

const Gallery: React.FC = () => {
  const [filter, setFilter] = useState<'All' | 'Race' | 'Training' | 'Social'>('All');

  // Lightbox State
  const [selectedAlbum, setSelectedAlbum] = useState<Album | null>(null);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [isLightboxOpen, setIsLightboxOpen] = useState(false);

  const filteredAlbums = filter === 'All' 
    ? GALLERY_ALBUMS 
    : GALLERY_ALBUMS.filter(album => album.tag === filter);

  const openAlbum = (album: Album) => {
    setSelectedAlbum(album);
    setCurrentImageIndex(0);
    setIsLightboxOpen(true);
    document.body.style.overflow = 'hidden'; 
  };

  const closeLightbox = useCallback(() => {
    setIsLightboxOpen(false);
    setSelectedAlbum(null);
    document.body.style.overflow = 'unset';
  }, []);

  const nextImage = useCallback((e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (selectedAlbum) {
      setCurrentImageIndex((prev) => (prev + 1) % selectedAlbum.images.length);
    }
  }, [selectedAlbum]);

  const prevImage = useCallback((e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (selectedAlbum) {
      setCurrentImageIndex((prev) => (prev - 1 + selectedAlbum.images.length) % selectedAlbum.images.length);
    }
  }, [selectedAlbum]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isLightboxOpen) return;
      if (e.key === 'Escape') closeLightbox();
      if (e.key === 'ArrowRight') nextImage();
      if (e.key === 'ArrowLeft') prevImage();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isLightboxOpen, closeLightbox, nextImage, prevImage]);

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement>) => {
    e.currentTarget.src = 'https://images.unsplash.com/photo-1552674605-469523f9bc9d?auto=format&fit=crop&q=80&w=600';
  };

  return (
    <div className="bg-white min-h-screen">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 animate-fade-in">
        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-end mb-12 gap-6">
          <div>
            <span className="text-teal-600 font-bold uppercase tracking-widest text-xs mb-2 block">Khoảnh khắc đáng nhớ</span>
            <h1 className="text-4xl font-display font-bold text-slate-900 flex items-center">
              THƯ VIỆN ẢNH
            </h1>
          </div>

          <div className="bg-gray-100 p-1.5 rounded-xl inline-flex">
             {['All', 'Race', 'Training', 'Social'].map((f) => (
               <button
                 key={f}
                 onClick={() => setFilter(f as any)}
                 className={`px-5 py-2 rounded-lg text-sm font-bold transition-all ${
                   filter === f 
                    ? 'bg-white text-slate-900 shadow-sm' 
                    : 'text-slate-500 hover:text-slate-800'
                 }`}
               >
                 {f === 'All' ? 'Tất cả' : f}
               </button>
             ))}
          </div>
        </div>

        {/* Album Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredAlbums.map((album) => (
            <div 
              key={album.id} 
              className="group cursor-pointer relative"
              onClick={() => openAlbum(album)}
            >
              <div className="relative h-72 rounded-2xl overflow-hidden shadow-sm group-hover:shadow-xl transition-all duration-500">
                 <img 
                   src={album.coverUrl} 
                   alt={album.title} 
                   className="w-full h-full object-cover transform transition-transform duration-700 group-hover:scale-110"
                   onError={handleImageError}
                 />

                 <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-slate-900/20 to-transparent opacity-80 group-hover:opacity-60 transition-opacity"></div>

                 <div className="absolute top-4 right-4 bg-white/20 backdrop-blur-md text-white px-3 py-1 rounded-full text-xs font-bold flex items-center border border-white/20">
                    <ImageIcon size={14} className="mr-1.5" /> {album.images.length}
                 </div>

                 <div className="absolute bottom-0 left-0 p-6 w-full text-white transform translate-y-2 group-hover:translate-y-0 transition-transform duration-500">
                   <div className="flex items-center space-x-2 mb-2">
                      <span className="text-[10px] font-bold uppercase tracking-widest bg-teal-600 px-2 py-0.5 rounded text-white">{album.tag}</span>
                      <span className="text-xs font-medium text-slate-300 flex items-center"><Calendar size={12} className="mr-1" /> {album.date}</span>
                   </div>
                   <h3 className="text-xl font-bold leading-tight mb-2 group-hover:text-teal-200 transition-colors">{album.title}</h3>
                   <p className="text-slate-300 text-sm line-clamp-1 opacity-0 group-hover:opacity-100 transition-opacity duration-500 delay-100">{album.description}</p>
                 </div>
              </div>
            </div>
          ))}
        </div>

        {/* Lightbox */}
        {isLightboxOpen && selectedAlbum && (
          <div className="fixed inset-0 z-[100] flex flex-col bg-slate-950/95 backdrop-blur-md animate-fade-in h-screen w-screen overflow-hidden">

            <div className="flex-shrink-0 flex justify-between items-center px-6 py-4 text-white z-[101]">
               <div>
                  <h3 className="font-bold text-lg">{selectedAlbum.title}</h3>
                  <p className="text-xs text-slate-400 font-mono mt-0.5">
                    Ảnh {currentImageIndex + 1} / {selectedAlbum.images.length}
                  </p>
               </div>
               <button 
                 onClick={closeLightbox} 
                 className="p-2 bg-white/10 hover:bg-white/20 rounded-full transition-colors focus:outline-none"
               >
                  <X size={24} />
               </button>
            </div>

            <div className="flex-1 min-h-0 relative flex items-center justify-center p-4 group" onClick={closeLightbox}>
               <img 
                 src={selectedAlbum.images[currentImageIndex].url} 
                 alt="Gallery"
                 className="max-h-full max-w-full object-contain shadow-2xl rounded-lg select-none"
                 onClick={(e) => e.stopPropagation()} 
                 onError={handleImageError}
               />

               <button 
                 className="absolute left-4 top-1/2 -translate-y-1/2 p-4 text-white/70 hover:text-white bg-black/20 hover:bg-black/40 rounded-full transition-all md:flex hidden backdrop-blur-sm"
                 onClick={prevImage}
               >
                 <ChevronLeft size={32} />
               </button>
               <button 
                 className="absolute right-4 top-1/2 -translate-y-1/2 p-4 text-white/70 hover:text-white bg-black/20 hover:bg-black/40 rounded-full transition-all md:flex hidden backdrop-blur-sm"
                 onClick={nextImage}
               >
                 <ChevronRight size={32} />
               </button>
            </div>

            <div className="flex-shrink-0 h-24 bg-black/40 flex items-center justify-center relative z-[101]">
               <div className="flex items-center space-x-3 overflow-x-auto px-4 py-2 w-full max-w-4xl justify-center h-full">
                 {selectedAlbum.images.map((img, idx) => (
                    <button 
                      key={idx}
                      onClick={(e) => { e.stopPropagation(); setCurrentImageIndex(idx); }}
                      className={`relative h-16 w-24 flex-shrink-0 rounded-lg overflow-hidden transition-all duration-300 border-2 ${
                        currentImageIndex === idx 
                          ? 'border-teal-500 opacity-100 scale-105 shadow-lg shadow-teal-500/20' 
                          : 'border-transparent opacity-40 hover:opacity-80 hover:scale-105 grayscale hover:grayscale-0'
                      }`}
                    >
                       <img 
                         src={img.url} 
                         className="w-full h-full object-cover" 
                         alt="Thumbnail" 
                         onError={handleImageError} 
                       />
                    </button>
                 ))}
               </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Gallery;

